text:
This will patch/compile with the 3.1-RELEASE sources.

Thanks
John

--- mv.org	Wed May  5 12:29:46 1999
+++ mv.c	Wed May  5 12:44:55 1999
@@ -64,7 +64,7 @@

 #include "pathnames.h"

-int fflg, iflg;
+int fflg, iflg, vflg;

 int	copy __P((char *, char *));
 int	do_move __P((char *, char *));
@@ -82,7 +82,7 @@
 	int ch;
 	char path[MAXPATHLEN];

-	while ((ch = getopt(argc, argv, "fi")) != -1)
+	while ((ch = getopt(argc, argv, "fiv")) != -1)
 		switch (ch) {
 		case 'i':
 			iflg = 1;
@@ -92,6 +92,9 @@
 			fflg = 1;
 			iflg = 0;
 			break;
+		case 'v':
+			vflg=1;
+			break;
 		default:
 			usage();
 		}
@@ -178,6 +181,9 @@
 			    group_from_gid(sb.st_gid, 0), to, YESNO);
 			ask = 1;
 		}
+		if(vflg) {
+			(void)fprintf(stderr, "Moving %s to %s\n", from, to);
+		}
 		if (ask) {
 			first = ch = getchar();
 			while (ch != '\n' && ch != EOF)
@@ -351,7 +357,7 @@
 usage()
 {
 	(void)fprintf(stderr, "%s\n%s\n",
-		      "usage: mv [-f | -i] source target",
-		      "       mv [-f | -i] source ... directory");
+		      "usage: mv [-f | -i] [-v] source target",
+		      "       mv [-f | -i] [-v] source ... directory");
 	exit(1);
 }
